import fs from "node:fs";
import path from "node:path";

const typescriptLibDir = path.resolve("node_modules", "typescript", "lib");
const shimPath = path.join(typescriptLibDir, "typescript.js");
const modernEntrypointPath = path.join(typescriptLibDir, "_tsc.js");
const compatMarker = "Generated by scripts/ensure-typescript-compat.mjs";

if (!fs.existsSync(typescriptLibDir)) {
  console.log("typescript compatibility check skipped: node_modules/typescript not found");
  process.exit(0);
}

if (!fs.existsSync(modernEntrypointPath)) {
  console.log("typescript compatibility check skipped: _tsc.js not found");
  process.exit(0);
}

const existingShim = fs.existsSync(shimPath) ? fs.readFileSync(shimPath, "utf8") : "";
if (existingShim && !existingShim.includes(compatMarker) && !existingShim.includes('require("./_tsc.js")')) {
  console.log("typescript compatibility check: existing compatible typescript.js found");
  process.exit(0);
}

const shimSource = `// ${compatMarker}
// electron-builder currently expects lib/typescript.js to export the compiler API.
const fs = require("node:fs");
const path = require("node:path");
const Module = module.constructor;

const sourcePath = path.join(__dirname, "_tsc.js");
let source = fs.readFileSync(sourcePath, "utf8");
source = source.replace(
  /\\nexecuteCommandLine\\(sys, noop, sys\\.args\\);\\s*\\/\\/# sourceMappingURL=_tsc\\.js\\.map\\s*$/,
  \`\\nmodule.exports = {
  version: typeof version !== "undefined" ? version : undefined,
  sys: typeof sys !== "undefined" ? sys : undefined,
  createCompilerHost: typeof createCompilerHost !== "undefined" ? createCompilerHost : undefined,
  createProgram: typeof createProgram !== "undefined" ? createProgram : undefined,
  findConfigFile: typeof findConfigFile !== "undefined" ? findConfigFile : undefined,
  flattenDiagnosticMessageText: typeof flattenDiagnosticMessageText !== "undefined" ? flattenDiagnosticMessageText : undefined,
  formatDiagnostics: typeof formatDiagnostics !== "undefined" ? formatDiagnostics : undefined,
  formatDiagnosticsWithColorAndContext:
    typeof formatDiagnosticsWithColorAndContext !== "undefined" ? formatDiagnosticsWithColorAndContext : undefined,
  getPreEmitDiagnostics: typeof getPreEmitDiagnostics !== "undefined" ? getPreEmitDiagnostics : undefined,
  ModuleKind: typeof ModuleKind !== "undefined" ? ModuleKind : undefined,
  ModuleResolutionKind: typeof ModuleResolutionKind !== "undefined" ? ModuleResolutionKind : undefined,
  parseJsonConfigFileContent: typeof parseJsonConfigFileContent !== "undefined" ? parseJsonConfigFileContent : undefined,
  readConfigFile: typeof readConfigFile !== "undefined" ? readConfigFile : undefined,
  ScriptTarget: typeof ScriptTarget !== "undefined" ? ScriptTarget : undefined,
  transpileModule: typeof transpileModule !== "undefined" ? transpileModule : undefined,
};\\n\`,
);

const compiledModule = new Module(sourcePath, module.parent);
compiledModule.filename = sourcePath;
compiledModule.paths = module.paths;
compiledModule._compile(source, sourcePath);
module.exports = compiledModule.exports;
`;

fs.writeFileSync(shimPath, shimSource, "utf8");
console.log("typescript compatibility shim created at lib/typescript.js");
